Code.Terraform:
```hcl
# Terraform: 少なくとも 3 つのデータノードを確保し、ゾーンアウェアネスを有効にします
resource "aws_opensearch_domain" "<example_resource_name>" {
  domain_name = "<example_resource_name>"

  cluster_config {
    instance_type          = "m5.large.search"
    instance_count         = 3     # 重要: フォールトトレランスのために少なくとも 3 つのデータノードを設定します
    zone_awareness_enabled = true  # 重要: クロス AZ (ゾーンアウェアネス) を有効にします
  }
}
```
